// frontend/src/services/webBluetoothService.js
class WebBluetoothService {
    constructor() {
        this.device = null;
        this.server = null;
        this.service = null;
        this.txCharacteristic = null;
        this.rxCharacteristic = null;
        this.isConnected = false;
        this.eventListeners = {};
    }

    async connect() {
        if (!navigator.bluetooth) {
            throw new Error('Web Bluetooth is not supported in this browser. Please use Chrome or Edge.');
        }

        try {
            console.log('🔍 Scanning for fingerprint sensor...');
            
            // Try multiple filter options for better discovery
            let device = null;
            
            try {
                // Try with name filter first
                device = await navigator.bluetooth.requestDevice({
                    filters: [
                        { name: 'E-Health_Fingerprint' },
                        { name: 'E-Health Fingerprint' },
                        { namePrefix: 'E-Health' }
                    ],
                    optionalServices: ['4fafc201-1fb5-459e-8fcc-c5c9c331914b']
                });
            } catch (nameError) {
                console.log('Name filter failed, trying with service UUID...');
                // Fallback to service UUID filter
                device = await navigator.bluetooth.requestDevice({
                    filters: [
                        { services: ['4fafc201-1fb5-459e-8fcc-c5c9c331914b'] }
                    ]
                });
            }
            
            if (!device) {
                throw new Error('No device selected');
            }
            
            console.log('✅ Device found:', device.name, device.id);
            this.device = device;
            
            // Handle disconnection
            this.device.addEventListener('gattserverdisconnected', () => {
                console.log('❌ Device disconnected');
                this.isConnected = false;
                this.emit('disconnected');
            });
            
            console.log('🔗 Connecting to GATT server...');
            this.server = await this.device.gatt.connect();
            
            console.log('📡 Getting service...');
            this.service = await this.server.getPrimaryService('4fafc201-1fb5-459e-8fcc-c5c9c331914b');
            
            console.log('📥 Getting RX characteristic...');
            this.rxCharacteristic = await this.service.getCharacteristic('beb5483e-36e1-4688-b7f5-ea07361b26a8');
            
            console.log('📤 Getting TX characteristic...');
            this.txCharacteristic = await this.service.getCharacteristic('beb5483e-36e1-4688-b7f5-ea07361b26a9');
            
            // Start notifications on RX characteristic (where ESP32 sends data)
            await this.rxCharacteristic.startNotifications();
            this.rxCharacteristic.addEventListener('characteristicvaluechanged', 
                this.handleNotification.bind(this));
            
            this.isConnected = true;
            console.log('✅ Fully connected to fingerprint sensor!');
            
            // Test connection
            await this.sendCommand('PING');
            
            return { success: true };
        } catch (error) {
            console.error('❌ Connection error:', error);
            return { success: false, error: error.message };
        }
    }

    handleNotification(event) {
        const value = event.target.value;
        const decoder = new TextDecoder('utf-8');
        const response = decoder.decode(value);
        console.log('📨 Received:', response);
        
        this.emit('data', response);
    }

    async sendCommand(command) {
        if (!this.isConnected || !this.txCharacteristic) {
            throw new Error('Not connected to device');
        }
        
        const encoder = new TextEncoder();
        await this.txCharacteristic.writeValue(encoder.encode(command + '\n'));
        console.log('📤 Sent:', command);
    }

    async scanFingerprint() {
        return new Promise((resolve, reject) => {
            const timeout = setTimeout(() => {
                reject(new Error('Scan timeout'));
            }, 10000);
            
            const handler = (response) => {
                if (response.startsWith('SCAN_SUCCESS')) {
                    clearTimeout(timeout);
                    const match = response.match(/ID=(\d+),CONFIDENCE=(\d+)/);
                    resolve({
                        success: true,
                        userId: match ? parseInt(match[1]) : null,
                        confidence: match ? parseInt(match[2]) : 0
                    });
                } else if (response.startsWith('SCAN_FAIL')) {
                    clearTimeout(timeout);
                    reject(new Error(response));
                }
            };
            
            this.once('data', handler);
            this.sendCommand('SCAN').catch(reject);
        });
    }

    async enrollFingerprint() {
        return new Promise((resolve, reject) => {
            const timeout = setTimeout(() => {
                reject(new Error('Enrollment timeout'));
            }, 30000);
            
            const handler = (response) => {
                if (response.startsWith('ENROLL_SUCCESS')) {
                    clearTimeout(timeout);
                    const match = response.match(/ID=(\d+)/);
                    resolve({
                        success: true,
                        userId: match ? parseInt(match[1]) : null
                    });
                } else if (response.startsWith('ENROLL_FAIL')) {
                    clearTimeout(timeout);
                    reject(new Error(response));
                } else if (response.startsWith('ENROLL_START')) {
                    console.log('📝 Place finger on sensor');
                } else if (response.startsWith('ENROLL_STEP')) {
                    console.log('📝', response);
                }
            };
            
            this.once('data', handler);
            this.sendCommand('ENROLL').catch(reject);
        });
    }

    on(event, callback) {
        if (!this.eventListeners[event]) {
            this.eventListeners[event] = [];
        }
        this.eventListeners[event].push(callback);
    }

    once(event, callback) {
        const wrapper = (...args) => {
            callback(...args);
            this.off(event, wrapper);
        };
        this.on(event, wrapper);
    }

    off(event, callback) {
        if (this.eventListeners[event]) {
            this.eventListeners[event] = this.eventListeners[event].filter(cb => cb !== callback);
        }
    }

    emit(event, data) {
        if (this.eventListeners[event]) {
            this.eventListeners[event].forEach(callback => callback(data));
        }
    }

    disconnect() {
        if (this.device && this.device.gatt.connected) {
            this.device.gatt.disconnect();
        }
        this.isConnected = false;
        console.log('Disconnected from device');
    }
}

export default WebBluetoothService;
